/**
 * Order Flow Integration Tests
 *
 * Integration tests for the order flow covering:
 * - Complete order creation → confirmation → preparation → delivery → completion flow
 * - Order CRUD operations
 * - Status workflow management with transitions
 * - Order item management (add, update, remove)
 * - Multi-tenant data isolation
 * - Error handling and edge cases
 *
 * These tests verify the interaction between OrderService,
 * CartService, TableRepository, and related components.
 *
 * @module tests/integration/order.integration.spec
 */

import { describe, it, expect, beforeEach, vi, type Mock } from 'vitest';

import { OrderService } from '@/modules/order/order.service';
import { CartService, type Cart, type CartItem } from '@/modules/order/cart.service';
import { AppException } from '@/core/exceptions/app.exception';
import type { EventService } from '@/core/services/event.service';
import type {
  Order,
  OrderWithRelations,
  OrderItem,
  OrderStatus,
  OrderType,
  OrderItemStatus,
  Table,
  CreateOrderRequest,
} from '@/modules/order/order.types';
import type { OrderRepository, PaginatedResult, CreateOrderItemData } from '@/modules/order/order.repository';
import type { TableRepository } from '@/modules/order/table.repository';

// -----------------------------------------------------------------------------
// Test Utilities & Factories
// -----------------------------------------------------------------------------

/**
 * Creates a mock OrderRepository
 */
function createMockOrderRepository(): Record<string, Mock> {
  return {
    findAll: vi.fn(),
    findAllSummaries: vi.fn(),
    findById: vi.fn(),
    findByIdWithRelations: vi.fn(),
    findByIdOrThrow: vi.fn(),
    findByOrderNumber: vi.fn(),
    findActiveOrders: vi.fn(),
    findByStatus: vi.fn(),
    orderNumberExists: vi.fn(),
    count: vi.fn(),
    getNextOrderNumber: vi.fn(),
    create: vi.fn(),
    update: vi.fn(),
    updateStatus: vi.fn(),
    recalculateTotals: vi.fn(),
    getOrderItems: vi.fn(),
    addOrderItem: vi.fn(),
    updateOrderItem: vi.fn(),
    updateOrderItemStatus: vi.fn(),
    removeOrderItem: vi.fn(),
    getOrderItem: vi.fn(),
    getOrderItemOrThrow: vi.fn(),
    getStatistics: vi.fn(),
  };
}

/**
 * Creates a mock TableRepository
 */
function createMockTableRepository(): Record<string, Mock> {
  return {
    findById: vi.fn(),
    findByIdOrThrow: vi.fn(),
    setCurrentOrder: vi.fn(),
    updateStatus: vi.fn(),
  };
}

/**
 * Creates a mock EventService that tracks emitted events
 */
function createMockEventService(): {
  emitCustom: Mock;
  getEmittedEvents: () => Array<{ event: string; data: unknown }>;
} {
  const emittedEvents: Array<{ event: string; data: unknown }> = [];

  return {
    emitCustom: vi.fn().mockImplementation(async (event: string, data: unknown) => {
      emittedEvents.push({ event, data });
    }),
    getEmittedEvents: () => [...emittedEvents],
  };
}

/**
 * Creates a mock order for testing
 */
function createMockOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order_integration_test',
    organizationId: 'org_integration_test',
    branchId: null,
    orderNumber: 'ORD-20260201-0001',
    tableId: null,
    customerId: null,
    staffId: null,
    status: 'PENDING' as OrderStatus,
    type: 'DINE_IN' as OrderType,
    subtotal: 100,
    taxAmount: 10,
    discountAmount: 0,
    totalAmount: 110,
    currency: 'TRY',
    notes: null,
    confirmedAt: null,
    preparedAt: null,
    deliveredAt: null,
    completedAt: null,
    cancelledAt: null,
    cancelReason: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock order with relations
 */
function createMockOrderWithRelations(
  overrides: Partial<OrderWithRelations> = {}
): OrderWithRelations {
  return {
    ...createMockOrder(),
    items: [],
    table: null,
    customer: null,
    feedback: null,
    ...overrides,
  };
}

/**
 * Creates a mock order item for testing
 */
function createMockOrderItem(overrides: Partial<OrderItem> = {}): OrderItem {
  return {
    id: 'item_integration_test',
    orderId: 'order_integration_test',
    productId: 'prod_integration_test',
    variantId: null,
    productName: 'Integration Test Product',
    variantName: null,
    quantity: 2,
    unitPrice: 50,
    totalPrice: 100,
    modifiers: [],
    notes: null,
    status: 'PENDING' as OrderItemStatus,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

/**
 * Creates a mock table for testing
 */
function createMockTable(overrides: Partial<Table> = {}): Table {
  return {
    id: 'table_integration_test',
    organizationId: 'org_integration_test',
    branchId: null,
    zoneId: null,
    number: '1',
    capacity: 4,
    status: 'AVAILABLE',
    currentOrderId: null,
    sortOrder: 0,
    createdAt: new Date(),
    updatedAt: new Date(),
    deletedAt: null,
    ...overrides,
  };
}

// -----------------------------------------------------------------------------
// Integration Test Suite
// -----------------------------------------------------------------------------

describe('Order Flow Integration', () => {
  let orderService: OrderService;
  let mockOrderRepository: ReturnType<typeof createMockOrderRepository>;
  let mockTableRepository: ReturnType<typeof createMockTableRepository>;
  let mockEventService: ReturnType<typeof createMockEventService>;

  const orgId = 'org_integration_test';

  beforeEach(() => {
    // Create fresh mocks for each test
    mockOrderRepository = createMockOrderRepository();
    mockTableRepository = createMockTableRepository();
    mockEventService = createMockEventService();

    // Create service instance with mocks
    orderService = new OrderService(
      mockOrderRepository as unknown as OrderRepository,
      mockTableRepository as unknown as TableRepository,
      mockEventService as unknown as EventService
    );
  });

  // ---------------------------------------------------------------------------
  // Complete Order Flow: Create → Confirm → Prepare → Ready → Deliver → Complete
  // ---------------------------------------------------------------------------

  describe('Complete Order Flow: Create → Confirm → Prepare → Ready → Deliver → Complete', () => {
    it('should complete full order lifecycle for dine-in order', async () => {
      // STEP 1: Create a new order
      const createOrderData: CreateOrderRequest = {
        tableId: 'table_integration_test',
        type: 'DINE_IN',
        items: [
          { productId: 'prod_1', quantity: 2 },
          { productId: 'prod_2', quantity: 1 },
        ],
        notes: 'No onions please',
      };

      // Setup mocks for order creation
      const table = createMockTable();
      mockTableRepository.findById.mockResolvedValue(table);
      mockOrderRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0001');

      const createdOrder = createMockOrder({
        tableId: 'table_integration_test',
        notes: 'No onions please',
      });
      mockOrderRepository.create.mockResolvedValue(createdOrder);

      const orderWithRelations = createMockOrderWithRelations({
        tableId: 'table_integration_test',
        items: [
          createMockOrderItem({ id: 'item_1', productId: 'prod_1', quantity: 2 }),
          createMockOrderItem({ id: 'item_2', productId: 'prod_2', quantity: 1 }),
        ],
        table,
      });
      mockOrderRepository.findByIdWithRelations.mockResolvedValue(orderWithRelations);

      const createResult = await orderService.create(orgId, createOrderData);

      // Verify order creation
      expect(createResult.order).toBeDefined();
      expect(createResult.order.status).toBe('PENDING');
      expect(createResult.order.type).toBe('DINE_IN');
      expect(createResult.message).toContain('successfully');

      // Verify table was linked
      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_integration_test',
        orgId,
        createdOrder.id
      );

      // Verify creation event
      let events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'order.created')).toBe(true);

      // STEP 2: Confirm the order
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED', confirmedAt: new Date() });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockOrderRepository.updateStatus.mockResolvedValue(confirmedOrder);

      const confirmResult = await orderService.confirm(orgId, createdOrder.id);

      expect(confirmResult.order.status).toBe('CONFIRMED');
      expect(confirmResult.previousStatus).toBe('PENDING');

      // Verify status change event
      events = mockEventService.getEmittedEvents();
      expect(
        events.some(
          (e) =>
            e.event === 'order.status_changed' &&
            (e.data as { newStatus: string }).newStatus === 'CONFIRMED'
        )
      ).toBe(true);

      // STEP 3: Start preparing
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(confirmedOrder);
      const preparingOrder = createMockOrder({ status: 'PREPARING', preparedAt: new Date() });
      mockOrderRepository.updateStatus.mockResolvedValue(preparingOrder);

      const prepareResult = await orderService.startPreparing(orgId, createdOrder.id);

      expect(prepareResult.order.status).toBe('PREPARING');
      expect(prepareResult.previousStatus).toBe('CONFIRMED');

      // STEP 4: Mark as ready
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(preparingOrder);
      const readyOrder = createMockOrder({ status: 'READY' });
      mockOrderRepository.updateStatus.mockResolvedValue(readyOrder);

      const readyResult = await orderService.markReady(orgId, createdOrder.id);

      expect(readyResult.order.status).toBe('READY');
      expect(readyResult.previousStatus).toBe('PREPARING');

      // STEP 5: Mark as delivered
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(readyOrder);
      const deliveredOrder = createMockOrder({ status: 'DELIVERED', deliveredAt: new Date() });
      mockOrderRepository.updateStatus.mockResolvedValue(deliveredOrder);

      const deliverResult = await orderService.markDelivered(orgId, createdOrder.id);

      expect(deliverResult.order.status).toBe('DELIVERED');
      expect(deliverResult.previousStatus).toBe('READY');

      // STEP 6: Complete the order
      mockOrderRepository.findByIdOrThrow.mockResolvedValue({
        ...deliveredOrder,
        tableId: 'table_integration_test',
      });
      const completedOrder = createMockOrder({
        status: 'COMPLETED',
        completedAt: new Date(),
        tableId: 'table_integration_test',
      });
      mockOrderRepository.updateStatus.mockResolvedValue(completedOrder);

      const completeResult = await orderService.complete(orgId, createdOrder.id);

      expect(completeResult.order.status).toBe('COMPLETED');
      expect(completeResult.previousStatus).toBe('DELIVERED');

      // Verify table was cleared on completion
      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_integration_test',
        orgId,
        null
      );

      // Verify all status change events were emitted
      const allEvents = mockEventService.getEmittedEvents();
      const statusEvents = allEvents.filter((e) => e.event === 'order.status_changed');
      expect(statusEvents).toHaveLength(5); // CONFIRMED, PREPARING, READY, DELIVERED, COMPLETED
    });

    it('should complete order flow for takeaway order', async () => {
      // Create takeaway order
      const createOrderData: CreateOrderRequest = {
        type: 'TAKEAWAY',
        items: [{ productId: 'prod_1', quantity: 1 }],
      };

      mockOrderRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0002');

      const createdOrder = createMockOrder({ type: 'TAKEAWAY' });
      mockOrderRepository.create.mockResolvedValue(createdOrder);
      mockOrderRepository.findByIdWithRelations.mockResolvedValue(
        createMockOrderWithRelations({ type: 'TAKEAWAY' })
      );

      const createResult = await orderService.create(orgId, createOrderData);

      expect(createResult.order.type).toBe('TAKEAWAY');

      // Verify table was NOT linked for takeaway
      expect(mockTableRepository.setCurrentOrder).not.toHaveBeenCalled();
    });

    it('should maintain referential integrity through the flow', async () => {
      // Create order linked to table
      const table = createMockTable({ id: 'table_ref_test' });
      const order = createMockOrder({
        id: 'order_ref_test',
        tableId: 'table_ref_test',
      });

      mockTableRepository.findById.mockResolvedValue(table);
      mockOrderRepository.getNextOrderNumber.mockResolvedValue('ORD-20260201-0003');
      mockOrderRepository.create.mockResolvedValue(order);
      mockOrderRepository.findByIdWithRelations.mockResolvedValue(
        createMockOrderWithRelations({
          id: 'order_ref_test',
          tableId: 'table_ref_test',
          table,
        })
      );

      const createResult = await orderService.create(orgId, {
        tableId: 'table_ref_test',
        type: 'DINE_IN',
        items: [{ productId: 'prod_1', quantity: 1 }],
      });

      // Verify order is linked to correct table
      expect(createResult.order.tableId).toBe('table_ref_test');
      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_ref_test',
        orgId,
        'order_ref_test'
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Order CRUD Operations
  // ---------------------------------------------------------------------------

  describe('Order CRUD Operations', () => {
    it('should create multiple orders with unique order numbers', async () => {
      // First order
      mockOrderRepository.getNextOrderNumber.mockResolvedValueOnce('ORD-20260201-0001');
      const order1 = createMockOrder({ id: 'order_1', orderNumber: 'ORD-20260201-0001' });
      mockOrderRepository.create.mockResolvedValueOnce(order1);
      mockOrderRepository.findByIdWithRelations.mockResolvedValueOnce(
        createMockOrderWithRelations({ id: 'order_1', orderNumber: 'ORD-20260201-0001' })
      );

      const result1 = await orderService.create(orgId, {
        type: 'TAKEAWAY',
        items: [{ productId: 'prod_1', quantity: 1 }],
      });

      expect(result1.order.orderNumber).toBe('ORD-20260201-0001');

      // Second order
      mockOrderRepository.getNextOrderNumber.mockResolvedValueOnce('ORD-20260201-0002');
      const order2 = createMockOrder({ id: 'order_2', orderNumber: 'ORD-20260201-0002' });
      mockOrderRepository.create.mockResolvedValueOnce(order2);
      mockOrderRepository.findByIdWithRelations.mockResolvedValueOnce(
        createMockOrderWithRelations({ id: 'order_2', orderNumber: 'ORD-20260201-0002' })
      );

      const result2 = await orderService.create(orgId, {
        type: 'TAKEAWAY',
        items: [{ productId: 'prod_2', quantity: 1 }],
      });

      expect(result2.order.orderNumber).toBe('ORD-20260201-0002');

      // Verify two creation events
      const events = mockEventService.getEmittedEvents();
      const createdEvents = events.filter((e) => e.event === 'order.created');
      expect(createdEvents).toHaveLength(2);
    });

    it('should update order notes successfully', async () => {
      const existingOrder = createMockOrder({ status: 'PENDING' });
      const updatedOrder = createMockOrder({
        notes: 'Updated customer notes',
      });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(existingOrder);
      mockOrderRepository.update.mockResolvedValue(updatedOrder);

      const result = await orderService.update(orgId, existingOrder.id, {
        notes: 'Updated customer notes',
      });

      expect(result.order.notes).toBe('Updated customer notes');
      expect(result.message).toContain('successfully');

      // Verify update event
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'order.updated')).toBe(true);
    });

    it('should get order by ID with relations', async () => {
      const items = [
        createMockOrderItem({ id: 'item_1', productName: 'Burger' }),
        createMockOrderItem({ id: 'item_2', productName: 'Fries' }),
      ];
      const table = createMockTable();
      const orderWithRelations = createMockOrderWithRelations({
        items,
        table,
      });

      mockOrderRepository.findByIdWithRelations.mockResolvedValue(orderWithRelations);

      const result = await orderService.getByIdWithRelations(orgId, 'order_integration_test', [
        'items',
        'table',
      ]);

      expect(result).toBeDefined();
      expect(result.items).toHaveLength(2);
      expect(result.table).toBeDefined();
    });

    it('should get order by order number', async () => {
      const order = createMockOrder({ orderNumber: 'ORD-20260201-0001' });
      mockOrderRepository.findByOrderNumber.mockResolvedValue(order);

      const result = await orderService.getByOrderNumber(orgId, 'ORD-20260201-0001');

      expect(result).toBeDefined();
      expect(result?.orderNumber).toBe('ORD-20260201-0001');
      expect(mockOrderRepository.findByOrderNumber).toHaveBeenCalledWith(
        orgId,
        'ORD-20260201-0001'
      );
    });

    it('should list orders with pagination', async () => {
      const orders = [
        createMockOrder({ id: 'order_1' }),
        createMockOrder({ id: 'order_2' }),
      ];
      const paginatedResult: PaginatedResult<Order> = {
        data: orders,
        meta: { page: 1, perPage: 20, total: 2, totalPages: 1 },
      };
      mockOrderRepository.findAll.mockResolvedValue(paginatedResult);

      const result = await orderService.list(orgId, { page: 1, perPage: 20 });

      expect(result.data).toHaveLength(2);
      expect(result.meta.total).toBe(2);
    });

    it('should list orders filtered by status', async () => {
      const pendingOrders = [createMockOrder({ status: 'PENDING' })];
      const paginatedResult: PaginatedResult<Order> = {
        data: pendingOrders,
        meta: { page: 1, perPage: 20, total: 1, totalPages: 1 },
      };
      mockOrderRepository.findAll.mockResolvedValue(paginatedResult);

      await orderService.list(orgId, { status: 'PENDING' });

      expect(mockOrderRepository.findAll).toHaveBeenCalledWith(
        orgId,
        expect.objectContaining({ status: 'PENDING' })
      );
    });

    it('should get active orders', async () => {
      const activeOrders = [
        createMockOrder({ status: 'PENDING' }),
        createMockOrder({ id: 'order_2', status: 'CONFIRMED' }),
        createMockOrder({ id: 'order_3', status: 'PREPARING' }),
      ];
      mockOrderRepository.findActiveOrders.mockResolvedValue(activeOrders);

      const result = await orderService.getActiveOrders(orgId);

      expect(result).toHaveLength(3);
      expect(mockOrderRepository.findActiveOrders).toHaveBeenCalledWith(orgId, undefined);
    });

    it('should get orders by status', async () => {
      const preparingOrders = [
        createMockOrder({ status: 'PREPARING' }),
        createMockOrder({ id: 'order_2', status: 'PREPARING' }),
      ];
      mockOrderRepository.findByStatus.mockResolvedValue(preparingOrders);

      const result = await orderService.getByStatus(orgId, 'PREPARING');

      expect(result).toHaveLength(2);
      expect(mockOrderRepository.findByStatus).toHaveBeenCalledWith(orgId, 'PREPARING');
    });
  });

  // ---------------------------------------------------------------------------
  // Status Workflow Management
  // ---------------------------------------------------------------------------

  describe('Status Workflow Management', () => {
    it('should follow valid status transitions', async () => {
      // Define the valid transition path
      const transitions: Array<{ from: OrderStatus; to: OrderStatus }> = [
        { from: 'PENDING', to: 'CONFIRMED' },
        { from: 'CONFIRMED', to: 'PREPARING' },
        { from: 'PREPARING', to: 'READY' },
        { from: 'READY', to: 'DELIVERED' },
        { from: 'DELIVERED', to: 'COMPLETED' },
      ];

      for (const transition of transitions) {
        const fromOrder = createMockOrder({ status: transition.from });
        const toOrder = createMockOrder({ status: transition.to });

        mockOrderRepository.findByIdOrThrow.mockResolvedValue(fromOrder);
        mockOrderRepository.updateStatus.mockResolvedValue(toOrder);

        const result = await orderService.changeStatus(orgId, 'order_test', {
          status: transition.to,
        });

        expect(result.order.status).toBe(transition.to);
        expect(result.previousStatus).toBe(transition.from);
      }
    });

    it('should reject invalid status transitions', async () => {
      // Cannot go from PENDING directly to COMPLETED
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);

      await expect(
        orderService.changeStatus(orgId, 'order_test', { status: 'COMPLETED' })
      ).rejects.toThrow(AppException);
    });

    it('should reject transition from COMPLETED to any status', async () => {
      const completedOrder = createMockOrder({ status: 'COMPLETED' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(completedOrder);

      // Try to go back to PENDING
      await expect(
        orderService.changeStatus(orgId, 'order_test', { status: 'PENDING' })
      ).rejects.toThrow(AppException);

      // Try to go to CONFIRMED
      await expect(
        orderService.changeStatus(orgId, 'order_test', { status: 'CONFIRMED' })
      ).rejects.toThrow(AppException);
    });

    it('should reject transition from CANCELLED to any status', async () => {
      const cancelledOrder = createMockOrder({ status: 'CANCELLED' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(cancelledOrder);

      await expect(
        orderService.changeStatus(orgId, 'order_test', { status: 'PENDING' })
      ).rejects.toThrow(AppException);
    });

    it('should allow cancellation from PENDING with reason (manager)', async () => {
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const cancelledOrder = createMockOrder({
        status: 'CANCELLED',
        cancelReason: 'Customer changed mind',
        cancelledAt: new Date(),
      });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockOrderRepository.updateStatus.mockResolvedValue(cancelledOrder);

      const result = await orderService.cancel(
        orgId,
        'order_test',
        'Customer changed mind',
        { role: 'manager' }
      );

      expect(result.order.status).toBe('CANCELLED');
      expect(result.message).toContain('cancelled');
    });

    it('should require reason for cancellation', async () => {
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);

      await expect(
        orderService.changeStatus(
          orgId,
          'order_test',
          { status: 'CANCELLED' },
          { role: 'manager' }
        )
      ).rejects.toThrow(AppException);
    });

    it('should not allow customer to cancel non-PENDING order', async () => {
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(confirmedOrder);

      await expect(
        orderService.changeStatus(
          orgId,
          'order_test',
          { status: 'CANCELLED', reason: 'Want to cancel' },
          { role: 'customer' }
        )
      ).rejects.toThrow(AppException);
    });

    it('should allow manager to cancel PREPARING order', async () => {
      const preparingOrder = createMockOrder({ status: 'PREPARING' });
      const cancelledOrder = createMockOrder({
        status: 'CANCELLED',
        cancelReason: 'Kitchen issue',
      });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(preparingOrder);
      mockOrderRepository.updateStatus.mockResolvedValue(cancelledOrder);

      const result = await orderService.cancel(
        orgId,
        'order_test',
        'Kitchen issue',
        { role: 'manager' }
      );

      expect(result.order.status).toBe('CANCELLED');
    });

    it('should clear table status on cancellation for dine-in orders', async () => {
      const dineInOrder = createMockOrder({
        status: 'PENDING',
        tableId: 'table_test',
        type: 'DINE_IN',
      });
      const cancelledOrder = createMockOrder({
        status: 'CANCELLED',
        tableId: 'table_test',
      });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(dineInOrder);
      mockOrderRepository.updateStatus.mockResolvedValue(cancelledOrder);

      await orderService.cancel(orgId, 'order_test', 'Customer left', { role: 'manager' });

      expect(mockTableRepository.setCurrentOrder).toHaveBeenCalledWith(
        'table_test',
        orgId,
        null
      );
    });
  });

  // ---------------------------------------------------------------------------
  // Order Item Management
  // ---------------------------------------------------------------------------

  describe('Order Item Management', () => {
    it('should add item to pending order', async () => {
      const pendingOrder = createMockOrder({ status: 'PENDING' });
      const newItem = createMockOrderItem({
        id: 'item_new',
        productId: 'prod_new',
        quantity: 3,
      });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(pendingOrder);
      mockOrderRepository.addOrderItem.mockResolvedValue(newItem);
      mockOrderRepository.recalculateTotals.mockResolvedValue(pendingOrder);

      const result = await orderService.addItem(orgId, 'order_test', {
        productId: 'prod_new',
        quantity: 3,
      });

      expect(result.item).toBeDefined();
      expect(result.item.productId).toBe('prod_new');
      expect(result.item.quantity).toBe(3);
      expect(result.message).toContain('added');

      // Verify event
      const events = mockEventService.getEmittedEvents();
      expect(events.some((e) => e.event === 'order.item_added')).toBe(true);
    });

    it('should add item to confirmed order', async () => {
      const confirmedOrder = createMockOrder({ status: 'CONFIRMED' });
      const newItem = createMockOrderItem({ id: 'item_new' });

      mockOrderRepository.findByIdOrThrow.mockResolvedValue(confirmedOrder);
      mockOrderRepository.addOrderItem.mockResolvedValue(newItem);
      mockOrderRepository.recalculateTotals.mockResolvedValue(confirmedOrder);

      const result = await orderService.addItem(orgId, 'order_test', {
        productId: 'prod_1',
        quantity: 1,
      });

      expect(result.item).toBeDefined();
    });

    it('should not add item to preparing or later orders', async () => {
      const preparingOrder = createMockOrder({ status: 'PREPARING' });
      mockOrderRepository.findByIdOrThrow.mockResolvedValue(preparingOrder);

      await expect(
        orderService.addItem(orgId, 'order_test', {
          productId: 'prod_1',
          quantity: 1,
        })
      ).rejects.toThrow(AppException);
    });

